let scene,camera,renderer,globe,clouds;function init3DPlanet(){const e=document.querySelector(".planet-sphere-container");if(!e)return;const t=document.createElement("canvas");t.id="canvas-3d-planet";e.appendChild(t);scene=new THREE.Scene;camera=new THREE.PerspectiveCamera(45,1,.1,1e3);camera.position.z=18;renderer=new THREE.WebGLRenderer({canvas:t,alpha:true,antialias:true});renderer.setSize(e.clientWidth,e.clientHeight);renderer.setPixelRatio(window.devicePixelRatio);const n=new THREE.AmbientLight(16777215,.3);scene.add(n);const o=new THREE.DirectionalLight(16777215,1.2);o.position.set(5,3,5);scene.add(o);const a=new THREE.DirectionalLight(54015,1);a.position.set(-5,3,-5);scene.add(a);const i=new THREE.SphereGeometry(6,64,64);const r=new THREE.MeshStandardMaterial({color:16777215,roughness:.6,metalness:.1});globe=new THREE.Mesh(i,r);scene.add(globe);const s=new THREE.SphereGeometry(6.1,64,64);const d=new THREE.MeshPhongMaterial({color:16777215,transparent:true,opacity:.2,blending:THREE.AdditiveBlending,side:THREE.DoubleSide});clouds=new THREE.Mesh(s,d);scene.add(clouds);let c=false;let l={x:0,y:0};t.addEventListener("mousedown",e=>{c=true});window.addEventListener("mouseup",()=>{c=false});window.addEventListener("mousemove",e=>{if(c){const t={x:e.offsetX-l.x,y:e.offsetY-l.y};globe.rotation.y+=t.x*.01;globe.rotation.x+=t.y*.01;clouds.rotation.y+=t.x*.012;clouds.rotation.x+=t.y*.012}l={x:e.offsetX,y:e.offsetY}});window.addEventListener("resize",()=>{if(!e)return;renderer.setSize(e.clientWidth,e.clientHeight);camera.aspect=e.clientWidth/e.clientHeight;camera.updateProjectionMatrix()});function E(){requestAnimationFrame(E);if(!c){globe.rotation.y+=.003;if(clouds){clouds.rotation.y+=.004;clouds.rotation.z+=5e-4}}renderer.render(scene,camera)}E()}function updatePlanetTexture3D(e){if(!globe)return;const t=new THREE.TextureLoader;t.load(e,e=>{e.anisotropy=renderer.capabilities.getMaxAnisotropy();globe.material.map=e;globe.material.needsUpdate=true;globe.material.displacementMap=e;globe.material.displacementScale=.2})}